// resolve-runtime-config — Code node
// Reads and validates all required environment variables.
// Returns the runtime config object for downstream use.
//
// IMPORTANT: No credential values are read here. Only credential NAMES
// (which identify credentials in n8n's vault) are read from env vars.
// The actual credential validation requires n8n-internal access — see
// workflows/runtime/credential-resolution-spec.md open question #1.
//
// SELF-HOSTED: All STORE_OS_* env vars are read from process.env.
//
// CLOUD MODE (n8n Cloud): process and require('fs') are not available.
// Pass a smoke_test_config in the trigger input to supply config values:
//   {
//     "smoke_test_config": {
//       "STORE_OS_OPENAI_CREDENTIAL_NAME": "OpenAI account",
//       "STORE_OS_SHOPIFY_CREDENTIAL_NAME": "Shopify account",
//       "STORE_OS_SHOPIFY_SHOP_URL": "my-store.myshopify.com",
//       "STORE_OS_LLM_MODEL": "gpt-4o",
//       "STORE_OS_ENV": "dev",
//       "STORE_OS_SHOPIFY_API_VERSION": "2024-01"
//     }
//   }

// Cloud-mode detection: n8n Cloud exposes neither require('fs') nor process
let cloudMode = false;
try { require('fs'); } catch (_e) { cloudMode = true; }
if (typeof process === 'undefined') { cloudMode = true; }

// Extract trigger input early — needed for cloud config fallback
const triggerInput = $input.first().json;

// Cloud-safe env accessor
// Self-hosted: reads from process.env
// Cloud:       reads from trigger input's smoke_test_config object
const smokeConfig = (cloudMode && triggerInput.smoke_test_config) ? triggerInput.smoke_test_config : {};
const getEnv = cloudMode
  ? (key) => { const v = smokeConfig[key]; return (v && String(v).trim()) ? String(v).trim() : null; }
  : (key) => { const v = process.env[key]; return (v && v.trim()) ? v.trim() : null; };

// Core vars required in both cloud and self-hosted modes
const REQUIRED_ENV_VARS_CORE = [
  'STORE_OS_OPENAI_CREDENTIAL_NAME',
  'STORE_OS_SHOPIFY_CREDENTIAL_NAME',
  'STORE_OS_SHOPIFY_SHOP_URL',
  'STORE_OS_LLM_MODEL',
  'STORE_OS_ENV',
  'STORE_OS_SHOPIFY_API_VERSION',
];

// Filesystem vars only required in self-hosted mode
const REQUIRED_ENV_VARS_FS = ['STORE_OS_PROJECT_ROOT', 'STORE_OS_AJV_SCHEMA_PATH'];

const REQUIRED_ENV_VARS = cloudMode
  ? REQUIRED_ENV_VARS_CORE
  : [...REQUIRED_ENV_VARS_CORE, ...REQUIRED_ENV_VARS_FS];

const ALLOWED_ENVS = ['dev', 'staging', 'production'];

// Step 1: Check all required env vars are set and non-empty
const missing = REQUIRED_ENV_VARS.filter((v) => !getEnv(v));
if (missing.length > 0) {
  throw new Error(
    'CONFIG_MISSING: Required environment variables not set: ' +
    missing.join(', ') +
    (cloudMode
      ? '. In n8n Cloud, pass these as smoke_test_config in the trigger input JSON.'
      : '. Configure them in n8n Settings > Variables or the n8n process environment.')
  );
}

// Step 2: Validate STORE_OS_ENV is an allowed value
const env = getEnv('STORE_OS_ENV');
if (!ALLOWED_ENVS.includes(env)) {
  throw new Error(
    `CONFIG_MISSING: STORE_OS_ENV must be one of: ${ALLOWED_ENVS.join(', ')}. Got: "${env}"`
  );
}

// Steps 3-4: Filesystem path validation — self-hosted only
// CLOUD SKIP: fs.existsSync requires local filesystem, not available in n8n Cloud
let fs;
let projectRoot = null;
let ajvSchemaPath = null;

if (!cloudMode) {
  fs = require('fs');
  projectRoot = getEnv('STORE_OS_PROJECT_ROOT');
  if (!fs.existsSync(projectRoot)) {
    throw new Error(
      `CONFIG_MISSING: STORE_OS_PROJECT_ROOT does not exist: ${projectRoot}. ` +
      'Create the directory and ensure it is writable by the n8n process.'
    );
  }

  ajvSchemaPath = getEnv('STORE_OS_AJV_SCHEMA_PATH');
  if (!fs.existsSync(ajvSchemaPath)) {
    throw new Error(
      `CONFIG_MISSING: STORE_OS_AJV_SCHEMA_PATH does not exist: ${ajvSchemaPath}. ` +
      'Point this to the store-os schemas/ directory.'
    );
  }
}

// Step 5: Assemble runtime config (no credential values — names only)
const runtimeConfig = {
  env,
  project_root:            projectRoot,
  openai_credential_name:  getEnv('STORE_OS_OPENAI_CREDENTIAL_NAME'),
  shopify_credential_name: getEnv('STORE_OS_SHOPIFY_CREDENTIAL_NAME'),
  shopify_shop_url:        getEnv('STORE_OS_SHOPIFY_SHOP_URL'),
  llm_model:               getEnv('STORE_OS_LLM_MODEL'),
  shopify_api_version:     getEnv('STORE_OS_SHOPIFY_API_VERSION'),
  allow_theme_writes:      getEnv('STORE_OS_ALLOW_THEME_WRITES') === 'true',
  shopify_theme_id:        getEnv('STORE_OS_SHOPIFY_THEME_ID'),
  allow_media_generation:  getEnv('STORE_OS_ALLOW_MEDIA_GENERATION') === 'true',
  media_generation_model:  getEnv('STORE_OS_MEDIA_GENERATION_MODEL') || 'dall-e-3',
  ajv_schema_path:         ajvSchemaPath,
  backup_root:             getEnv('STORE_OS_BACKUP_ROOT'),
  resolved_at:             new Date().toISOString(),
  cloud_mode:              cloudMode,
};

if (cloudMode) {
  console.warn(
    'CLOUD_MODE: Running in n8n Cloud compatibility mode. ' +
    'Config read from trigger input smoke_test_config. ' +
    'Filesystem operations (project_root, ajv_schema_path) are disabled. ' +
    'Artifact persistence and schema validation are not available in this mode.'
  );
}

return [{ json: { runtime_config: runtimeConfig, status: 'SUCCESS' } }];
